    \caption{Layer preference of different experts. Most experts are used in multiple layers, while some of them (see, bottom right) specialize to certain layers, showing the flexibility of our model.\label{fig:expert_dist}}
\end{minipage}
\hfill
\begin{minipage}{0.47\textwidth}
    \centering
    \includegraphics[height=3.3cm]{figures/expert_count_per_token_per_layer.pdf}
    \caption{No.\ of unique experts used in different layers.
    Tokens are routed to many different experts (depending on the context), especially in the middle layers.\label{fig:expert_per_token}}
